#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x1 = (int *)a;
    int *x2 = (int *)b;
    return x1[0] - x2[0];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int **kids = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            kids[i] = (int *)malloc(2 * sizeof(int));
            scanf("%d %d", &kids[i][0], &kids[i][1]);
        }
        qsort(kids, N, 2 * sizeof(int), compare);
        double minTime = -1;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                double time = (double)(kids[j][0] - kids[i][0]) / (kids[i][1] + kids[j][1]);
                if (minTime == -1 || time < minTime) {
                    minTime = time;
                }
            }
        }
        printf("%.6f\n", minTime);
        for (int i = 0; i < N; i++) {
            free(kids[i]);
        }
        free(kids);
    }
    return 0;
}

