import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Kid implements Comparable<Kid> {
        int x, v;
        Kid(int x, int v) {
            this.x = x;
            this.v = v;
        }
        public int compareTo(Kid other) {
            return this.x - other.x;
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            Kid[] kids = new Kid[N];
            for (int i = 0; i < N; i++) {
                kids[i] = new Kid(sc.nextInt(), sc.nextInt());
            }
            Arrays.sort(kids);
            double minTime = -1;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    double time = (double)(kids[j].x - kids[i].x) / (kids[i].v + kids[j].v);
                    if (minTime == -1 || time < minTime) {
                        minTime = time;
                    }
                }
            }
            System.out.printf("%.6f\n", minTime);
        }
    }
}

