const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextLine() {
    return lines[idx++];
}

function solve() {
    let T = nextInt();
    while (T-- > 0) {
        let N = nextInt();
        let kids = [];
        for (let i = 0; i < N; i++) {
            let [x, v] = nextLine().split(' ').map(Number);
            kids.push([x, v]);
        }
        kids.sort((a, b) => a[0] - b[0]);
        let minTime = -1;
        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                let time = (kids[j][0] - kids[i][0]) / (kids[i][1] + kids[j][1]);
                if (minTime == -1 || time < minTime) {
                    minTime = time;
                }
            }
        }
        console.log(minTime.toFixed(6));
    }
}

solve();

